@namespace Lumeo

@{
    var context = new CollapsibleContext(EffectiveOpen, EventCallback.Factory.Create(this, Toggle), _triggerId, _contentId, Disabled);
}

<div class="@CssClass"
     data-state="@(EffectiveOpen ? "open" : "closed")"
     data-disabled="@(Disabled ? string.Empty : null)"
     @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    /// <summary>
    /// When true the collapsible cannot be toggled: the trigger no-ops and every
    /// part (root/trigger/content) emits <c>data-disabled</c> so consumers can
    /// style the disabled state with a <c>data-[disabled]</c> selector (Radix parity).
    /// </summary>
    [Parameter] public bool Disabled { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Stable per-instance IDs so the trigger can render
    // aria-controls=ContentId and the content can render
    // aria-labelledby=TriggerId. Same pattern as Accordion.
    private readonly string _triggerId = LumeoIds.New("collapsible-trigger");
    private readonly string _contentId = LumeoIds.New("collapsible-content");

    // Uncontrolled state lives in a private backing field, NOT in the [Parameter]
    // Open. Blazor re-applies [Parameter] values from the parent on every render,
    // so self-managing state by writing back into Open got silently reset whenever
    // an unrelated parent re-render pushed the original Open value down. (#246)
    private bool _openState;
    private bool _initialized;
    private bool _lastOpenParam;

    /// <summary>
    /// State the component actually renders from. Controlled (OpenChanged bound):
    /// the parent owns it, so mirror Open verbatim. Uncontrolled: use our own
    /// backing field so parent re-renders can't clobber it.
    /// </summary>
    private bool EffectiveOpen => OpenChanged.HasDelegate ? Open : _openState;

    protected override void OnParametersSet()
    {
        // Seed the uncontrolled backing field from Open on first set (honours an
        // initial Open="true") and whenever the bound Open value actually changes
        // (lets callers still drive it imperatively via the parameter), but never
        // on the no-op re-applications that caused the reset (#246).
        //
        // Note: parameter-edge detection cannot tell a deliberate re-assert of the
        // SAME Open value from a no-op re-render, so a parent that wants to reopen
        // a panel the user has since closed — while Open already equals its last
        // value — must drive it through the OpenChanged binding (controlled mode)
        // or the imperative SetOpen(bool) method below, rather than re-setting the
        // unchanged Open parameter. (#74)
        if (!_initialized || Open != _lastOpenParam)
        {
            _openState = Open;
            _lastOpenParam = Open;
            _initialized = true;
        }
    }

    private string CssClass => Cx.Merge(Class);

    private async Task Toggle()
    {
        if (Disabled) return;
        var next = !EffectiveOpen;
        // Controlled (Open is bound via OpenChanged): let the parent own state —
        // fire the callback and render from the parent's next value instead of
        // mutating our own [Parameter], which desyncs if the parent rejects or
        // ignores the change. Uncontrolled: self-manage via the backing field. (#238, #246)
        if (OpenChanged.HasDelegate)
        {
            await OpenChanged.InvokeAsync(next);
        }
        else
        {
            _openState = next;
        }
    }

    /// <summary>
    /// Imperatively set the open state. In controlled mode (OpenChanged bound)
    /// this fires the callback so the parent stays the source of truth. In
    /// uncontrolled mode it drives the internal backing field directly, giving
    /// callers a reliable way to (re)assert open/closed without depending on the
    /// Open parameter being treated as a one-time default. Triggers a re-render.
    /// </summary>
    public async Task SetOpen(bool open)
    {
        if (OpenChanged.HasDelegate)
        {
            if (open != Open)
            {
                await OpenChanged.InvokeAsync(open);
            }
        }
        else if (open != _openState)
        {
            _openState = open;
            StateHasChanged();
        }
    }

    public record CollapsibleContext(bool IsOpen, EventCallback Toggle, string TriggerId, string ContentId, bool Disabled = false);
}

@namespace Lumeo

@* `invisible` while closed — see AccordionContent: keeps the close animation
   while removing focusable children from the tab order. *@
<div id="@Context.ContentId" role="region" aria-labelledby="@Context.TriggerId" class="grid transition-[grid-template-rows] duration-200 ease-out @(Context.IsOpen ? "grid-rows-[1fr] opacity-100" : "grid-rows-[0fr] opacity-0 invisible") @CssClass" data-state="@(Context.IsOpen ? "open" : "closed")" data-disabled="@(Context.Disabled ? string.Empty : null)" @attributes="AdditionalAttributes" aria-hidden="@(Context.IsOpen ? "false" : "true")">
    <div class="overflow-hidden min-h-0">
        @ChildContent
    </div>
</div>

@code {
    [CascadingParameter] public Collapsible.CollapsibleContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>
    /// Preserved for API compatibility only — Collapsible content is now
    /// always mounted so the grid-rows close animation can run on collapse,
    /// so this flag is effectively a no-op. Children always live in the DOM
    /// whether the collapsible is open or closed.
    /// </summary>
    [Parameter] public bool ForceMount { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(Class);
}

@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop

<div id="@Context.TriggerId" class="@CssClass" role="button" tabindex="@(Context.Disabled ? "-1" : "0")" aria-expanded="@(Context.IsOpen ? "true" : "false")" aria-controls="@Context.ContentId" aria-disabled="@(Context.Disabled ? "true" : null)" data-state="@(Context.IsOpen ? "open" : "closed")" data-disabled="@(Context.Disabled ? string.Empty : null)" @onclick="Context.Toggle" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public Collapsible.CollapsibleContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("cursor-pointer focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 rounded-sm", Class);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        try
        {
            // div[role=button] has no native key synthesis: Space toggled AND
            // scrolled the page. Suppress only Space's default (Enter has no
            // default on a div) synchronously in JS.
            await Interop.RegisterPreventDefaultKeys(
                Context.TriggerId,
                new[] { new Lumeo.Services.PreventDefaultKeyRule(" ") });
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    private bool _pdRegistered;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" || e.Key == " ")
        {
            await Context.Toggle.InvokeAsync();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered) return;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(Context.TriggerId);
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}
